import {{threading}}
import time

counter = 0
lock = threading.{{Lock}}()

def increment(n: int):
    global counter
    for _ in range(n):
        with {{lock}}:     # kritická sekce
            counter += {{1}}

# Spuštění více vláken
threads = []
for _ in range(5):
    t = threading.{{Thread}}(target=increment, args=(10000,))
    threads.{{append}}(t)
    t.{{start}}()

for t in {{threads}}:
    t.{{join}}()

print("Výsledek:", {{counter}})   # vždy 50000

# Producer-Consumer s frontou
from queue import {{Queue}}
q = Queue(maxsize={{10}})

def producer():
    for i in range(20):
        q.{{put}}(i)
        time.sleep(0.01)

def consumer():
    while True:
        item = q.{{get}}()
        if item is None: break
        print("Zpracovávám:", {{item}})
        q.{{task_done}}()
